#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, A, B;
        scanf("%lld %lld %lld", &X, &A, &B);
        long long sol = A + (100 - X) * B; // grams per 100 mL
        printf("%lld\n", sol * 10);
    }
    return 0;
}

